事务提交或回滚） 可以自行加锁： SELECT price FROM products WHERE id = 1 LOCK IN SHARE MODE; -- 加共享锁SELECT price FROM products WHERE id = 1 FOR UPDATE; -- 加排他锁 如果太久不释放行级锁，等待释放的事务会收到超时报错 例如： 在可重复读下 -- 事务 A 开始START TRANSACTION;-- 事务 A 读取数据SELECT price FROM products WHERE id = 1; -- 假设读取到价格为 100-- 如果改用共享锁，事务B会等待事务A释放锁-- 事务 B 开始START TRANSACTION;-- 事务 B 修改数据UPDATE products SET price = 200 WHERE id = 1;-- 事务 B 提交COMMIT;-- 事务 A 再次读取数据SELECT price FROM products WHERE id = 1; -- 仍然会读取到价格为 100，因为事务 A 读取的是快照中的数据-- 事务 A 提交COMMIT; 容易死锁（互相等释放） -- 事务 ASTART TRANSACTION;SELECT price FROM products WHERE id = 1 LOCK IN SHARE MODE;SELECT price FROM products WHERE id = 2 FOR UPDATE; -- 尝试获取 id = 2 的排他锁-- 事务 BSTART TRANSACTION;SELECT price FROM products WHERE id = 2 LOCK IN SHARE MODE;SELECT price FROM products WHERE id = 1 FOR UPDATE; -- 尝试获取 id = 1 的排他锁 串行化串行执行，最高级别 不是并发，所以不会幻读，但导致事务之间会相互阻塞，会极大地降低系统的吞吐量。 事务实例&lt;?php$dbhost = &#x27;localhost&#x27;; // mysql服务器主机地址$dbuser = &#x27;root&#x27;; // mysql用户名$dbpass = &#x27;123456&#x27;; // mysql用户名密码$conn = mysqli_connect($dbhost, $dbuser, $dbpass);if(! $conn )&#123; die(&#x27;连接失败: &#x27; . mysqli_error($conn));&#125;// 设置编码，防止中文乱码mysqli_query($conn, &quot;set names utf8&quot;);mysqli_select_db( $conn, &#x27;RUNOOB&#x27; );mysqli_query($conn, &quot;SET AUTOCOMMIT=0&quot;); // 设置为不自动提交，因为MYSQL默认立即执行mysqli_begin_transaction($conn); // 开始事务定义 if(!mysqli_query($conn, &quot;insert into runoob_transaction_test (id) values(8)&quot;))&#123; mysqli_query($conn, &quot;ROLLBACK&quot;); // 判断当执行失败时回滚&#125; if(!mysqli_query($conn, &quot;insert into runoob_transaction_test (id) values(9)&quot;))&#123; mysqli_query($conn, &quot;ROLLBACK&quot;); // 判断执行失败时回滚&#125;mysqli_commit($conn); //执行事务mysqli_close($conn);?&gt;
